/** Get small title for single line display */
export function getSmallTitle(theme = 'casino') {
    switch (theme) {
        case 'casino':
            return '🎰 TEXAS HOLD\'EM POKER 🎰';
        case 'modern':
            return '⬡ TEXAS HOLD\'EM POKER ⬡';
        case 'retro':
            return '👾 TEXAS HOLD\'EM POKER 👾';
    }
}
/** Get hand rank display */
export function getHandRankDisplay(rankName, theme = 'casino') {
    const borders = {
        casino: ['╔', '╗', '║', '═', '╚', '╝'],
        modern: ['┌', '┐', '│', '─', '└', '┘'],
        retro: ['+', '+', '|', '-', '+', '+']
    };
    const [tl, tr, v, h, bl, br] = borders[theme];
    const padding = 2;
    return `${tl}${h.repeat(rankName.length + padding * 2)}${tr}\n${v}${' '.repeat(padding)}${rankName}${' '.repeat(padding)}${v}\n${bl}${h.repeat(rankName.length + padding * 2)}${br}`;
}
